import math


def get_input() -> tuple[int, int, int]:
    return map(int, input().split())


def get_distance(x1: int, y1: int, x2: int, y2: int) -> float:
    return math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2)


def get_area_of_intersection(x1: int, y1: int, r1: int, x2: int, y2: int, r2: int) -> float:
    distance = get_distance(x1, y1, x2, y2)
    if distance > r1 + r2:
        return 0
    elif distance < abs(r1 - r2):
        return math.pi * min(r1, r2) ** 2
    else:
        return math.acos((r1 ** 2 + distance ** 2 - r2 ** 2) / (2 * r1 * distance)) * r1 ** 2 + math.acos(
            (r2 ** 2 + distance ** 2 - r1 ** 2) / (2 * r2 * distance)) * r2 ** 2 - 0.5 * (
                       r1 + r2 + distance) * math.sqrt(
            (r1 + r2 + distance) * (r1 + r2 - distance) * (r1 - r2 + distance) * (r2 - r1 + distance))


def main():
    x1, y1, r1 = get_input()
    x2, y2, r2 = get_input()
    print(get_area_of_intersection(x1, y1, r1, x2, y2, r2))


if __name__ == "__main__":
    main()
